1080 
1081   // MatchBB should be the entrypoint into the inner loop containing the
1082   // comparison between a search element and a needle.
1083   //
1084   // MatchBB:
1085   //   %20 = phi ptr [ %7, %Header ], [ %17, %InnerBB ]
