1191   if (!match(OuterBB->getTerminator(),
1192              m_Br(m_SpecificICmp(ICmpInst::ICMP_EQ, m_Specific(GEPSearch),
1193                                  m_Value(SearchEnd)),
1194                   m_BasicBlock(ExitFail), m_Specific(Header))))
