1197   if (!CurLoop->isLoopInvariant(SearchStart) ||
1198       !CurLoop->isLoopInvariant(SearchEnd) ||
1199       !CurLoop->isLoopInvariant(NeedleStart) ||
1200       !CurLoop->isLoopInvariant(NeedleEnd))
